sections.content:
// Matcher exato — só ativa para Edit
"matcher": "Edit"

// Wildcard — ativa para qualquer ferramenta
"matcher": "*"

// Regex — ativa para ferramentas MCP do GitHub
"matcher": "mcp__github__.*"

// Matcher específico — apenas Bash
"matcher": "Bash"

// Tipo command — executa um comando shell
{
  "type": "command",
  "command": "npx prettier --write $FILE_PATH"
}

// Tipo prompt — injeta uma instrução no Claude
{
  "type": "prompt",
  "prompt": "Verifique se a tarefa está completa. Retorne 'approve' para parar ou 'block' com motivo."
}

// O hook pode retornar:
{
  "decision": "approve",    // permite a ação
  "reason": "Validação OK"
}

// ou
{
  "decision": "block",       // bloqueia a ação
  "reason": "Arquivo protegido",
  "systemMessage": "Este arquivo não pode ser editado."
}
